var e=[{id:`L2_1`,type:`dialog`,speaker:`STAR_HUNTER_NULL_NULL`,text:{KOREA:`이번 작전이 끝나믄… 쌤, 저랑 데이트 한 번 하실랍니까? 제가 풀코스로 딱 모실 테니까예……`,JPN:`今回の作戦が終わったら……先生、1回ウチとデートしてくれへん？　ウチがフルコースでおもてなししますから……`,ENG:`Once this mission's done... how about a date, Teach? I'll treat you to the full course–`,TWN:`等這次作戰結束…老師，要不要和我約會一次？我會帶你跑全套行程……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`STAR_HUNTER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`STAR_HUNTER_NULL_NULL`,text:{KOREA:`앗!?`,JPN:`あっ！？`,ENG:`Wait!`,TWN:`啊！？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`STAR_HUNTER_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`STAR_HUNTER_NULL_NULL`,text:{KOREA:`이거 완전 사망 플래그네예!? 방금 소원은 무효! 무효!! 캔슬입니다!! `,JPN:`これ完全に死亡フラグやないか！　今のなし、なし！　前言撤回や！ `,ENG:`No, no, that's a death flag! Forget I said that! I take it back!!`,TWN:`這簡直是在立死旗吧！？剛才的願望無效！無效！！收回！！ `},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`STAR_HUNTER_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};